// Post-build script: reads the Vite manifest and generates dist/static/index.html
// for Firebase Hosting (static), then copies all client assets there.
import { readFileSync, writeFileSync, cpSync, mkdirSync, readdirSync } from "fs";
import { join } from "path";

const root = process.cwd();
const clientDir = join(root, "dist", "client");
const staticDir = join(root, "dist", "static");

// Read Vite manifest generated by build.manifest: true
const manifest = JSON.parse(
  readFileSync(join(clientDir, ".vite", "manifest.json"), "utf-8")
);

// Find the client entry chunk (isEntry: true)
const entryChunk = Object.values(manifest).find((chunk) => chunk.isEntry);
if (!entryChunk) throw new Error("No entry chunk found in Vite manifest");

const entryJs = `/assets/${entryChunk.file.replace("assets/", "")}`;

// Collect CSS from manifest AND scan assets dir (catches ?url imports not listed in manifest)
const manifestCss = (entryChunk.css ?? []).map((f) => `/assets/${f.replace("assets/", "")}`);
const scannedCss = readdirSync(join(clientDir, "assets"))
  .filter((f) => f.endsWith(".css"))
  .map((f) => `/assets/${f}`);
const cssFiles = [...new Set([...manifestCss, ...scannedCss])];

// Copy all client assets to dist/static
mkdirSync(staticDir, { recursive: true });
cpSync(clientDir, staticDir, { recursive: true });

// Generate index.html
const cssLinks = cssFiles
  .map((f) => `  <link rel="stylesheet" href="${f}" />`)
  .join("\n");

// TanStack Start's client hydration checks window.$_TSR and throws "Invariant
// failed" if absent. With empty matches and no lastMatchId, every route falls
// through to client-side loading (ssr=false / SPA mode) instead of hydration.
const bootstrap = `<script>window.$_TSR={router:{matches:[],lastMatchId:undefined},buffer:[],h:function(){}};<\/script>`;

const html = `<!DOCTYPE html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>School Harmony Hub</title>
    <link rel="preconnect" href="https://fonts.googleapis.com" />
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />
    <link rel="stylesheet" href="https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700;800&display=swap" />
${cssLinks}
    ${bootstrap}
    <script type="module" src="${entryJs}"></script>
  </head>
  <body>
  </body>
</html>
`;

writeFileSync(join(staticDir, "index.html"), html);
console.log(`Generated dist/static/index.html`);
console.log(`  Entry: ${entryJs}`);
console.log(`  CSS: ${cssFiles.join(", ")}`);
